        z             <= 32'd0;
        a_mantissa    <= 24'd0;
        b_mantissa    <= 24'd0;
        z_mantissa    <= 24'd0;
        a_exponent    <= 10'd0;
        b_exponent    <= 10'd0;
        z_exponent    <= 10'd0;
        a_sign        <= 1'b0;
        b_sign        <= 1'b0;
        z_sign        <= 1'b0;
        product       <= 50'd0;
        guard_bit     <= 1'b0;
        round_bit     <= 1'b0;
