module float_multi(
    input              clk,
    input              rst,
    input      [31:0]  a,
    input      [31:0]  b,
    output reg [31:0]  z
);

    // 1. Logic type:
    //    Sequential, multi-cycle datapath controlled by a small counter.
    //
    // 2. Key signals:
    //    - a_sign, b_sign, z_sign: result sign = a_sign ^ b_sign
    //    - a_exponent, b_exponent, z_exponent: exponent arithmetic with bias correction
    //    - a_mantissa, b_mantissa: 24-bit significands including hidden bit for normalized numbers
    //    - product: significand multiplication result
    //    - guard_bit, round_bit, sticky: rounding support
    //    - counter: sequences unpack -> special-case/prepare -> multiply/normalize -> round/output
    //
    // 3. Timing/reset:
    //    - Synchronous operation on clk
    //    - Active-high reset clears state and output
    //    - New inputs are sampled when counter returns to 0

    reg [2:0]  counter;

    reg [23:0] a_mantissa, b_mantissa, z_mantissa;
    reg [9:0]  a_exponent, b_exponent, z_exponent;
    reg        a_sign, b_sign, z_sign;

    reg [49:0] product;
    reg        guard_bit, round_bit, sticky;

    reg        a_is_nan, b_is_nan;
    reg        a_is_inf, b_is_inf;
    reg        a_is_zero, b_is_zero;
    reg        special_case;

    reg [31:0] z_temp;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            counter      <= 3'd0;
            z            <= 32'd0;

            a_mantissa   <= 24'd0;
            b_mantissa   <= 24'd0;
            z_mantissa   <= 24'd0;

            a_exponent   <= 10'd0;
            b_exponent   <= 10'd0;
            z_exponent   <= 10'd0;

            a_sign       <= 1'b0;
            b_sign       <= 1'b0;
            z_sign       <= 1'b0;

            product      <= 50'd0;

            guard_bit    <= 1'b0;
            round_bit    <= 1'b0;
            sticky       <= 1'b0;

            a_is_nan     <= 1'b0;
            b_is_nan     <= 1'b0;
            a_is_inf     <= 1'b0;
            b_is_inf     <= 1'b0;
            a_is_zero    <= 1'b0;
            b_is_zero    <= 1'b0;
            special_case <= 1'b0;
            z_temp       <= 32'd0;
        end else begin
            case (counter)
                // ------------------------------------------------------------
                // Cycle 0: unpack inputs
                // ------------------------------------------------------------
                3'd0: begin
                    a_sign <= a[31];
                    b_sign <= b[31];

                    a_is_nan  <= (a[30:23] == 8'hFF) && (a[22:0] != 23'd0);
                    b_is_nan  <= (b[30:23] == 8'hFF) && (b[22:0] != 23'd0);
                    a_is_inf  <= (a[30:23] == 8'hFF) && (a[22:0] == 23'd0);
                    b_is_inf  <= (b[30:23] == 8'hFF) && (b[22:0] == 23'd0);
                    a_is_zero <= (a[30:23] == 8'd0)  && (a[22:0] == 23'd0);
                    b_is_zero <= (b[30:23] == 8'd0)  && (b[22:0] == 23'd0);

                    // For normalized numbers, include hidden 1.
                    // For denormals, hidden bit is 0 and exponent is treated as 1 for arithmetic.
                    if (a[30:23] == 8'd0) begin
                        a_exponent <= 10'd1;
                        a_mantissa <= {1'b0, a[22:0]};
                    end else begin
                        a_exponent <= {2'b00, a[30:23]};
                        a_mantissa <= {1'b1, a[22:0]};
                    end

                    if (b[30:23] == 8'd0) begin
                        b_exponent <= 10'd1;
                        b_mantissa <= {1'b0, b[22:0]};
                    end else begin
                        b_exponent <= {2'b00, b[30:23]};
                        b_mantissa <= {1'b1, b[22:0]};
                    end

                    special_case <= 1'b0;
                    counter <= 3'd1;
                end

                // ------------------------------------------------------------
                // Cycle 1: special case handling / prepare arithmetic
                // ------------------------------------------------------------
                3'd1: begin
                    z_sign <= a_sign ^ b_sign;

                    if (a_is_nan || b_is_nan) begin
                        // Quiet NaN
                        z_temp       <= 32'h7FC00000;
                        special_case <= 1'b1;
                    end else if ((a_is_inf && b_is_zero) || (b_is_inf && a_is_zero)) begin
                        // inf * 0 = NaN
                        z_temp       <= 32'h7FC00000;
                        special_case <= 1'b1;
                    end else if (a_is_inf || b_is_inf) begin
                        // inf * finite non-zero = inf
                        z_temp       <= {(a_sign ^ b_sign), 8'hFF, 23'd0};
                        special_case <= 1'b1;
                    end else if (a_is_zero || b_is_zero) begin
                        // zero result
                        z_temp       <= {(a_sign ^ b_sign), 8'd0, 23'd0};
                        special_case <= 1'b1;
                    end else begin
                        // unbiased exponent sum with rebias adjustment later
                        z_exponent   <= a_exponent + b_exponent - 10'd127;
                        product      <= a_mantissa * b_mantissa; // 24x24 fits in 48 bits
                        special_case <= 1'b0;
                    end

                    counter <= 3'd2;
                end

                // ------------------------------------------------------------
                // Cycle 2: normalize product and extract rounding bits
                // ------------------------------------------------------------
                3'd2: begin
                    if (special_case) begin
                        z <= z_temp;
                        counter <= 3'd0;
                    end else begin
                        // product is effectively 48-bit significant in product[47:0]
                        // If MSB at bit 47 is 1, value is in [2,4), shift right by 1 and increment exponent.
                        if (product[47]) begin
                            z_mantissa <= product[47:24];   // includes hidden bit
                            guard_bit  <= product[23];
                            round_bit  <= product[22];
                            sticky     <= |product[21:0];
                            z_exponent <= z_exponent + 10'd1;
                        end else begin
                            z_mantissa <= product[46:23];   // includes hidden bit
                            guard_bit  <= product[22];
                            round_bit  <= product[21];
                            sticky     <= |product[20:0];
                        end
                        counter <= 3'd3;
                    end
                end

                // ------------------------------------------------------------
                // Cycle 3: round to nearest even
                // ------------------------------------------------------------
                3'd3: begin
                    if (guard_bit && (round_bit || sticky || z_mantissa[0])) begin
                        {z_exponent, z_mantissa} <= {z_exponent, z_mantissa} + 1'b1;
                    end
                    counter <= 3'd4;
                end

                // ------------------------------------------------------------
                // Cycle 4: pack result, handle overflow/underflow
                // ------------------------------------------------------------
                3'd4: begin
                    // If rounding overflowed mantissa (e.g. 1.111.. + 1 ulp -> 10.000..),
                    // renormalize by shifting right and incrementing exponent.
                    if (z_mantissa[23] == 1'b0 && z_exponent > 0) begin
                        // already normalized or subnormal path; no action needed
                    end

                    if (z_mantissa[23:22] == 2'b10) begin
                        z_mantissa <= z_mantissa >> 1;
                        z_exponent <= z_exponent + 10'd1;
                        counter    <= 3'd5;
                    end else begin
                        counter    <= 3'd5;
                    end
                end

                // ------------------------------------------------------------
                // Cycle 5: final output stage
                // ------------------------------------------------------------
                3'd5: begin
                    if (z_exponent >= 10'd255) begin
                        // overflow -> infinity
                        z <= {z_sign, 8'hFF, 23'd0};
                    end else if (z_exponent <= 10'd0) begin
                        // underflow -> zero (simple handling)
                        z <= {z_sign, 8'd0, 23'd0};
                    end else begin
                        z <= {z_sign, z_exponent[7:0], z_mantissa[22:0]};
                    end
                    counter <= 3'd0;
                end

                default: begin
                    counter <= 3'd0;
                end
            endcase
        end
    end

endmodule

