module multi_booth_8bit(
    input              clk,
    input              reset,
    input      [7:0]   a,
    input      [7:0]   b,
    output reg [15:0]  p,
    output reg         rdy
);

    reg signed [17:0] acc;
    reg signed [17:0] multiplicand_reg;
    reg        [9:0]  multiplier_reg;
    reg        [2:0]  ctr;

    function signed [17:0] booth_term;
        input [2:0] bits;
        input signed [17:0] x;
        begin
            case (bits)
                3'b001,
                3'b010: booth_term = x;
                3'b011: booth_term = (x <<< 1);
                3'b100: booth_term = - (x <<< 1);
                3'b101,
                3'b110: booth_term = -x;
                default: booth_term = 18'sd0;
            endcase
        end
    endfunction

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            acc             <= 18'sd0;
            multiplicand_reg<= {{10{a[7]}}, a};   // sign-extended multiplicand
            multiplier_reg  <= {b[7], b, 1'b0};   // sign-extended multiplier + Booth 0
            ctr             <= 3'd0;
            p               <= 16'd0;
            rdy             <= 1'b0;
