            multiplicand_reg<= (multiplicand_reg <<< 2);                      // left shift by 2

            if (ctr == 3) begin
                p   <= acc + booth_term(multiplier_reg[2:0], multiplicand_reg);
                rdy <= 1'b1;
            end

            ctr <= ctr + 3'd1;
        end
    end

