2. **Key signals:**  
   - `CLK`: advances the FSM state  
   - `RST`: active-high reset, returns FSM to idle  
   - `IN`: serial input bit stream  
   - `MATCH`: asserted when the FSM has seen `1001` and the current `IN` is `1`, completing `10011`
3. **Timing/reset:** State updates on `posedge CLK`; reset is asynchronous on `posedge RST`. Since this is a Mealy machine, `MATCH` is combinational from `state` and `IN`, and is forced low during reset. Overlap/continuous detection is supported.

```verilog
module fsm(
    input  IN,
    input  CLK,
    input  RST,
    output MATCH
);

    // State encoding for pattern 10011
    // S0 : no match
    // S1 : matched "1"
    // S2 : matched "10"
    // S3 : matched "100"
    // S4 : matched "1001"
    localparam S0 = 3'd0,
               S1 = 3'd1,
               S2 = 3'd2,
               S3 = 3'd3,
               S4 = 3'd4;

    reg [2:0] state, next_state;

    // State register with asynchronous active-high reset
    always @(posedge CLK or posedge RST) begin
        if (RST)
            state <= S0;
        else
            state <= next_state;
    end

    // Next-state logic
    always @(*) begin
        case (state)
            S0: next_state = IN ? S1 : S0;
            S1: next_state = IN ? S1 : S2;
            S2: next_state = IN ? S1 : S3;
            S3: next_state = IN ? S4 : S0;
            S4: next_state = IN ? S1 : S2;  // overlap support after 10011 / 10010
            default: next_state = S0;
        endcase
    end

    // Mealy output: assert on the same cycle as the last '1' of 10011
    assign MATCH = (!RST) && (state == S4) && IN;

endmodule
