        ST_IDLE = 3'd0,
        ST_S1   = 3'd1,
        ST_S2   = 3'd2,
        ST_S3   = 3'd3,
        ST_S4   = 3'd4;

    reg [2:0] current_state, next_state;

    // State register with active-low reset
    always @(posedge clk or negedge reset_n) begin
        if (!reset_n)
            current_state <= ST_IDLE;
        else
            current_state <= next_state;
    end

    // Next-state logic for detecting sequence 1001
    always @(*) begin
        case (current_state)
            ST_IDLE: begin
                if (data_in)
                    next_state = ST_S1;   // matched '1'
                else
                    next_state = ST_IDLE;
            end

            ST_S1: begin
                if (data_in)
                    next_state = ST_S1;   // still possible start with '1'
                else
                    next_state = ST_S2;   // matched '10'
            end

            ST_S2: begin
                if (data_in)
                    next_state = ST_S1;   // '101' -> possible new start at last '1'
